mapper.select:
SELECT B.GADMIN GADMIN, B.GADMINNM GADMINNM FROM TZ_MANAGER A, TZ_GADMIN B WHERE A.GADMIN = B.GADMIN
AND A.USERID = #{userid}
AND A.USERID = #{s_userid}
AND A.ISDELETED = 'N' AND TO_CHAR(SYSDATE,'YYYYMMDD') BETWEEN A.FMON AND A.TMON AND B.GADMIN != 'A217' ORDER BY B.SEQ, B.GADMIN
limit 100
